parameters.jsCode:
// 1. Safe JSON Parsing
let c = {};
try {
  // If the LLM returned markdown blocks like ```json ... ```, strip them out first
  const rawContent = $json.choices[0].message.content.replace(/```json|```/g, '').trim();
  c = JSON.parse(rawContent);
} catch (e) {
  throw new Error("Failed to parse LLM response. The returned content was not valid JSON: " + e.message);
}

// 2. Safely capture the previous node source text (using .first() is safer in Code nodes)
let sourceText = "";
try {
  sourceText = $('Set Input').first().json.source_text || "";
} catch (e) {
  // Fallback if 'Set Input' node isn't directly reachable or has a different structure
  sourceText = "";
}

// 3. Map the fields safely
return { 
  json: {
    title: c.title || "",
    hook: c.hook || "",
    twitter_caption: c.twitter_caption || "",
    linkedin_caption: c.linkedin_caption || "",
    instagram_caption: c.instagram_caption || "",
    // If hashtags is already a string, keep it; if array, join it; otherwise fallback to empty string
    hashtags: Array.isArray(c.hashtags) 
      ? c.hashtags.join(' ') 
      : (c.hashtags || ""),
    source_preview: sourceText.slice(0, 100),
    status: 'ready',
    created_at: $now.toISO()
  } 
};

