parameters.message:
={{ 
  (() => {
    try {
      const jsonMatch = $json.alert.match(/(\{.*\})/);
      if (jsonMatch) {
        const cleanJsonString = jsonMatch[1]
          .replace(/\\"/g, '"')
          .replace(/\\n/g, '');

        const errorObj = JSON.parse(cleanJsonString);
        const errorDetails = errorObj.error || {};

        // Extract the error code (e.g., 401) from the raw alert text
        const statusMatch = $json.alert.match(/(\d{3})/);
        const statusCode = statusMatch ? statusMatch[1] : 'N/A';

        return `
          <div style="font-family: Arial, sans-serif; max-width: 600px; border: 1px solid #e0e0e0; border-radius: 8px; overflow: hidden; box-shadow: 0 4px 6px rgba(0,0,0,0.05);">
            <div style="background-color: #e53e3e; color: white; padding: 15px 20px; font-size: 18px; font-weight: bold;">
              ⚠️ Content Pipeline Failure Alert
            </div>
            <div style="padding: 20px; background-color: #f7fafc;">
              <table style="width: 100%; border-collapse: collapse; background: white; border-radius: 6px; overflow: hidden;">
                <tr style="border-bottom: 1px solid #edf2f7;">
                  <td style="padding: 12px 15px; font-weight: bold; color: #4a5568; width: 30%;">Status Code:</td>
                  <td style="padding: 12px 15px; color: #e53e3e; font-weight: bold;">${statusCode}</td>
                </tr>
                <tr style="border-bottom: 1px solid #edf2f7;">
                  <td style="padding: 12px 15px; font-weight: bold; color: #4a5568;">Error Message:</td>
                  <td style="padding: 12px 15px; color: #2d3748; font-weight: 500;">${errorDetails.message || 'N/A'}</td>
                </tr>
                <tr style="border-bottom: 1px solid #edf2f7;">
                  <td style="padding: 12px 15px; font-weight: bold; color: #4a5568;">Error Type:</td>
                  <td style="padding: 12px 15px; color: #4a5568; font-family: monospace;">${errorDetails.type || 'N/A'}</td>
                </tr>
                <tr>
                  <td style="padding: 12px 15px; font-weight: bold; color: #4a5568;">Error Code:</td>
                  <td style="padding: 12px 15px; color: #718096; font-family: monospace;">${errorDetails.code || 'N/A'}</td>
                </tr>
              </table>
            </div>
            <div style="background-color: #edf2f7; padding: 12px 20px; text-align: right; font-size: 11px; color: #a0aec0;">
              System Alert • Generated automatically
            </div>
          </div>
        `;
      }
    } catch (e) {
      // Fallback
    }
    return `<h3>Content pipeline failed</h3><p>${$json.alert}</p>`;
  })()
}}
